import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/生活/理财.md","filePath":"ccc/生活/理财.md"}`),a={name:`ccc/生活/理财.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h2 id="理财" tabindex="-1">理财 <a class="header-anchor" href="#理财" aria-label="Permalink to “理财”">​</a></h2><p><strong>见好就收</strong></p><p><strong>见好就收</strong></p><p><strong>见好就收</strong></p><p>不要教条式机械的看待问题，典型如所谓“黄金是避险货币”，然而现实是一旦爆发流动性危机，往往会出售黄金回拢流动性，大部分垃圾资产在危机时是根本卖不出去，这往往导致优质资产反而在爆发危机时可能跌的更狠。ETF同理，也是典型。</p><h3 id="以下内容不需要" tabindex="-1">以下内容不需要 <a class="header-anchor" href="#以下内容不需要" aria-label="Permalink to “以下内容不需要”">​</a></h3><ol><li>公众号<code>梁中华宏观研究</code>海通证券的宏观经济观察。</li><li><a href="https://www.bilibili.com/video/BV1Ni4y177kY" target="_blank" rel="noreferrer">钱的创造过程</a></li><li><a href="https://www.morningstar.cn/quickrank/default.aspx" target="_blank" rel="noreferrer">晨星网</a></li></ol><h2 id="中国净主权信用货币年复合增速10" tabindex="-1">中国净主权信用货币年复合增速10% <a class="header-anchor" href="#中国净主权信用货币年复合增速10" aria-label="Permalink to “中国净主权信用货币年复合增速10%”">​</a></h2><p>截止21年，中国资产负债表年复合增速在18%左右，减去外汇占款，中国净主权信用货币的年复合增速在10%上下。</p><p>任何产品年化收益率比10%还高，就意味着风险很高，比印钱还来钱。</p><table tabindex="0"><thead><tr><th style="text-align:center;"></th><th style="text-align:center;">常见年化利率</th><th style="text-align:center;">买入</th></tr></thead><tbody><tr><td style="text-align:center;">定期存款</td><td style="text-align:center;">1.5%(1年)2.75%(3年)2.75%(5年)</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">宝宝类如余额宝，货币基金</td><td style="text-align:center;">2%~3%</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">短期理财产品(半年以内)</td><td style="text-align:center;">3.5%~4%</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">中期理财产品(半年~一年半)</td><td style="text-align:center;">4%~5%</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">短债基金</td><td style="text-align:center;">2%~5%(要扣去0.4%-0.6%的成本)</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">中长债（纯债）</td><td style="text-align:center;">1%~20%(要扣去0.4%-1%的成本)</td><td style="text-align:center;">十年期国债收益率历史高位</td></tr><tr><td style="text-align:center;">黄金</td><td style="text-align:center;">短期波动大</td><td style="text-align:center;">降息或有通胀预期</td></tr></tbody></table><p>  对冲基金从过往数据分析，风险和长债差不多，收益不如，成本高。</p><table tabindex="0"><thead><tr><th></th><th><strong>通常标准差</strong>(%)</th><th><strong>通常夏普比率</strong></th></tr></thead><tbody><tr><td>可转债</td><td>12-18</td><td>0.85-1.1</td></tr><tr><td>积极债券</td><td>8-12</td><td>0.9-1.3</td></tr><tr><td>积极配置</td><td>16-30</td><td>1.2-1.6</td></tr><tr><td>指数基金</td><td>15-32</td><td>0.8-0.95</td></tr></tbody></table><ul><li>标准差反映基金波动幅度，越大代表波动越大。</li><li>夏普比率代表基金承担单位风险得到的超额回报率越高。</li></ul><p>可转债波动较大，短期收益是相对比较高的。</p><p>从数据上看，指数基金的风险跟积极配置差不多，唯一优势就是持有成本低一点，收益却不如积极配置。</p><p><strong>以股票为主的基金，如指数基金经常有鼓吹长期持有的，我认为这类基金要有收益，得低位定投，高位尽早见好就收，长期持有我是觉得很亏。</strong>就最唐的低买高卖，保守来说一般年化利率10%还是有的。</p><p>需要少操作长期持有的，可以考虑定投红利指数，主要吃分红，年化收益大概4%~8%，但是短期可能会遇到比较大波动。</p><p>那些冻结一两年的产品有个3%~4%的其实不错了，毕竟稳。</p><ul><li>货币超发不一定会流入股市，还会流入大宗商品，汇市，楼市。</li></ul><p>假设某行业进入下行周期，理论上此时需要做的应该是逆周期调节，助力该行业相关企业度过难关。而不是做空像秃鹫一样蚕食该行业。</p><h4 id="基金乱象" tabindex="-1">基金乱象 <a class="header-anchor" href="#基金乱象" aria-label="Permalink to “基金乱象”">​</a></h4><p>大部分网红基金指数的历史走势是回测的，先射箭再竖靶。就没有历史数据不好看的网红指数，基金公司不是猪头三，买家也不是猪头三。</p><h5 id="老鼠仓" tabindex="-1">老鼠仓 <a class="header-anchor" href="#老鼠仓" aria-label="Permalink to “老鼠仓”">​</a></h5><p>基金经理先用自己的钱买股票再用客户资金拉高价格。</p><p>公募基金接盘，私募基金会和上市公司达成协议，一个抬价一个发布利好消息，股价抬高之后公司套现，获利和私募分成，私募基金接着会找公募基金接盘。</p><p>避免老鼠仓可以考虑买指数基金。</p><h5 id="抬轿子" tabindex="-1">抬轿子 <a class="header-anchor" href="#抬轿子" aria-label="Permalink to “抬轿子”">​</a></h5><p>每年年末公募基金会有排名战，有些公司会用抬轿子的套路抬高自己基金的排名，再通过砸盘影响友商排名。抬轿子指明星基金先买入一支股票坐轿子，其他基金持续买入抬轿子。如果同公司基金持仓相似度很高，业绩差距却很大就要小心，如果是小盘股嫌疑就更大。砸盘就是提前买入友商重仓的股票，年底了大量抛售。</p><h5 id="一拖多" tabindex="-1">一拖多 <a class="header-anchor" href="#一拖多" aria-label="Permalink to “一拖多”">​</a></h5><p>一个明星经理挂名多个基金。</p>`,31)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};